// Convert spot symbol to contract symbol format (optimized)
function toContractSymbol(symbol) {
  if (typeof symbol !== 'string' || !symbol) return symbol;

  // Fast path for USDT pairs (most common case)
  if (symbol.endsWith('USDT') && symbol.length > 4) {
    return `${symbol.slice(0, -4)}_USDT`;
  }

  // Common quote currencies (ordered by frequency)
  const QUOTES = ['BTC','ETH','USD','BUSD','TUSD'];

  for (const quote of QUOTES) {
    if (symbol.endsWith(quote) && symbol.length > quote.length) {
      return `${symbol.slice(0, -quote.length)}_${quote}`;
    }
  }

  return symbol; // Fallback to original
}

// Get coin name (optimized to top 15 coins)
function getCoinName(symbol) {
  if (typeof symbol !== 'string' || !symbol) return 'Unknown';

  // Extract base currency from symbol
  let base = symbol;
  const QUOTES = ['USDT', 'USD', 'BTC', 'ETH']; // Most common quotes only

  for (const quote of QUOTES) {
    if (symbol.endsWith(quote)) {
      base = symbol.slice(0, -quote.length);
      break;
    }
  }

  // Top 15 cryptocurrencies only (by market cap)
  const coinNames = {
    'BTC': 'Bitcoin',
    'ETH': 'Ethereum',
    'SOL': 'Solana',
    'XRP': 'Ripple',
    'BNB': 'Binance Coin',
