/**
 * Crypto Symbol Extractor for n8n
 * 
 * This code node sits between Chat Input and AI Agent nodes to:
 * 1. Generate a session ID for conversation tracking
 * 2. Extract cryptocurrency symbols from natural language
 * 3. Pass through the original chat input
 */

/**
 * Generates a unique session ID
 * @returns {string} A unique session identifier
 */
function generateSessionId() {
  // Timestamp component (milliseconds since epoch)
  const timestamp = Date.now();

  // Random component (8 random hex characters)
  const randomPart = Math.floor(Math.random() * 0xFFFFFFFF).toString(16).padStart(8, '0');

  // Combine to create a unique ID
  return `${timestamp.toString(16)}-${randomPart}`;
}

/**
 * Extracts cryptocurrency information from chat input
 * @param {string} chatInput - The user's chat message
 * @returns {object} Extracted crypto information
 */
function extractCryptoInfo(chatInput) {
  // Default to Bitcoin if no crypto is mentioned
  let coinName = 'bitcoin';
  let quoteAsset = 'USDT';

  // Common crypto keywords to look for
  const cryptoKeywords = {
    'bitcoin': 'BTC',
    'btc': 'BTC',
    'ethereum': 'ETH',
    'eth': 'ETH',
    'solana': 'SOL',
    'sol': 'SOL',
    'cardano': 'ADA',
    'ada': 'ADA',
    'ripple': 'XRP',
    'xrp': 'XRP',
    'polkadot': 'DOT',
    'dot': 'DOT',
    'avalanche': 'AVAX',
    'avax': 'AVAX',
    'dogecoin': 'DOGE',
    'doge': 'DOGE',
    'shiba': 'SHIB',
    'shibainu': 'SHIB',
    'polygon': 'MATIC',
    'matic': 'MATIC',
    'litecoin': 'LTC',
    'ltc': 'LTC',
    'chainlink': 'LINK',
    'link': 'LINK',
    'uniswap': 'UNI',
    'uni': 'UNI',
    'binance': 'BNB',
    'bnb': 'BNB'
  };

  // Check if any crypto keywords are in the chat input
  const normalizedInput = chatInput.toLowerCase();

  for (const [key, value] of Object.entries(cryptoKeywords)) {
    if (normalizedInput.includes(key)) {
      coinName = key;
      break;
    }
  }

  // Check for quote assets (USDT, BUSD, etc.)
  const quoteAssets = ['USDT', 'USD', 'BUSD', 'BTC', 'ETH'];
  for (const quote of quoteAssets) {
    if (normalizedInput.includes(quote.toLowerCase())) {
      quoteAsset = quote;
      break;
    }
  }

  // Get the symbol from the coin name
  const symbol = cryptoKeywords[coinName] || coinName.toUpperCase();

  return {
    coinName,
    symbol,
    tradingPair: `${symbol}${quoteAsset}`
  };
}

