// Helper: EMA calculation
function calculateEMA(data, period) {
  const k = 2 / (period + 1);
  let emaArray = [];
  let emaPrev;

  data.forEach((price, i) => {
    if (i === 0) {
      emaPrev = price;
      emaArray.push(emaPrev);
    } else {
      let ema = price * k + emaPrev * (1 - k);
      emaArray.push(ema);
      emaPrev = ema;
    }
  });
  return emaArray;
}

// Helper: RSI calculation
function calculateRSI(data, period) {
  let gains = 0;
  let losses = 0;
  let rsiArray = [];

  for (let i = 1; i < data.length; i++) {
    const diff = data[i] - data[i - 1];
    if (diff >= 0) {
      gains += diff;
    } else {
      losses -= diff;
    }
    if (i === period) {
      const avgGain = gains / period;
      const avgLoss = losses / period;
      let rs = avgGain / avgLoss;
      let rsi = 100 - 100 / (1 + rs);
      rsiArray[period] = rsi;

      let prevAvgGain = avgGain;
      let prevAvgLoss = avgLoss;

      for (let j = period + 1; j < data.length; j++) {
        const delta = data[j] - data[j - 1];
        let gain = delta > 0 ? delta : 0;
        let loss = delta < 0 ? -delta : 0;
        prevAvgGain = (prevAvgGain * (period - 1) + gain) / period;
        prevAvgLoss = (prevAvgLoss * (period - 1) + loss) / period;
        rs = prevAvgGain / prevAvgLoss;
        rsi = 100 - 100 / (1 + rs);
        rsiArray[j] = rsi;
      }
      break;
    }
  }
  return rsiArray;
}

// Extract close prices
