  timestamp: c.timestamp,
  close: parseFloat(c.close),
  ema12: ema12[i] || null,
  ema26: ema26[i] || null,
  macd: macd[i] || null,
  macdSignal: macdSignal[i - (macd.length - macdSignal.length)] || null,
  rsi: rsi[i] || null,
}));

// Return the JSON string of output directly:
return JSON.stringify(output);
